CREATE TABLE t_p86624306_task_monitoring_inte.tasks (id SERIAL PRIMARY KEY, number TEXT NOT NULL, title TEXT NOT NULL, description TEXT DEFAULT '', assigned_by TEXT NOT NULL DEFAULT 'Директор Петров В.И.', deadline DATE NOT NULL, status TEXT NOT NULL DEFAULT 'new' CHECK (status IN ('new','progress','done','overdue')), priority TEXT NOT NULL DEFAULT 'medium' CHECK (priority IN ('high','medium','low')), section TEXT NOT NULL DEFAULT 'order' CHECK (section IN ('order','report')), linked_order_id INTEGER, created_at TIMESTAMPTZ DEFAULT NOW())
